private static int greatestCommonDivisor(int u, int v) {
    if (u == 0) return Math.abs(v);
    if (v == 0) return Math.abs(u);

    if (u == Integer.MIN_VALUE || v == Integer.MIN_VALUE) {
        if (u == Integer.MIN_VALUE && v == Integer.MIN_VALUE) {
            return 1 << 31;
        } else if (u == Integer.MIN_VALUE) {
            return gcdPos(Math.abs(u), Math.abs(v));
        } else {
            return gcdPos(Math.abs(v), Math.abs(u));
        }
    }

    u = Math.abs(u);
    v = Math.abs(v);

    if (u == 1 || v == 1) {
        return 1;
    }

    int k = 0;
    while ((u & 1) == 0 && (v & 1) == 0 && k < 31) {
        u /= 2;
        v /= 2;
        k++;
    }

    if (k == 31) {
        throw new ArithmeticException("overflow: gcd is 2^31");
    }

    while (u != 0 && v != 0) {
        while ((u & 1) == 0) u /= 2;
        while ((v & 1) == 0) v /= 2;
        int diff = u - v;
        if (diff > 0) {
            u = diff / 2;
        } else {
            v = -diff / 2;
        }
    }

    return (u == 0 ? v : u) * (1 << k);
}

private static int gcdPos(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}
